import React from 'react';
import Logo from '../public/logo.svg';
function HEADER() {
    return (
        <>
            <nav className="border-bottom border-primary navbar navbar-dark bg-dark navbar-expand">
                <img className="navbar-brand" src={Logo} height="50" alt="logo" />
                <ul className="navbar-nav mr-auto mt-2 mt-lg-0">
                    <li className="nav-item active">
                        <a className="nav-link" href="/">Profissional <span className="sr-only">(current)</span></a>
                    </li>
                    <li className="nav-item">
                        <a className="nav-link" href="/galeria">Portifólio</a>
                    </li>
                    <li className="nav-item">
                        <a className="nav-link" href="/contato">Contato</a>
                    </li>
                </ul>
            </nav>
        </>
    );
}

export default HEADER;
